# NORMALIZACIÓN
# ══════════════════════════════════════════════════════════════════════════════
EMP_ALIASES = {
    "KAUFMAN": "KAUFMANN",
    "FALABELLA - VALPARAISO": "FALABELLA - VALPARAÍSO",
    "FALABELLA - SERENA": "FALABELLA - LA SERENA",
    "TRADIS LOGISTICA FALABELLA": "TRADIS LOGÍSTICA FALABELLA",
    "TIO TOMATE": "TÍO TOMATE",
    "TRP": "APOYO TRP",
}
CANON = {
    "KAUFMANN": "KAUFMANN",
    "FALABELLA - RM": "Falabella - RM",
    "FALABELLA - RANCAGUA": "Falabella - Rancagua",
    "FALABELLA - ANTOFAGASTA": "Falabella - Antofagasta",
    "FALABELLA - IQUIQUE": "Falabella - Iquique",
    "FALABELLA - VALDIVIA": "Falabella - Valdivia",
    "FALABELLA - VALPARAÍSO": "Falabella - Valparaíso",
    "FALABELLA - LA SERENA": "Falabella - La Serena",
    "FALABELLA - TALCA": "Falabella - Talca",
    "TRADIS LOGÍSTICA FALABELLA": "TRADIS Logística Falabella",
    "TÍO TOMATE": "Tío Tomate",
    "SODIMAC - CORONEL": "Sodimac - Coronel",
    "GRUPO ALCANSA": "Grupo Alcansa",
    "ANDES MOTOR": "Andes Motor",
    "APOYO TRP": "APOYO TRP",
}
TIPO_AR = {
    "SALIDA CALENDARIZADA": "REGULAR", "SALIDA REALIZADA": "REGULAR",
    "SERVICIO REGULAR": "REGULAR", "SERVICIO ESPECIAL": "SPOT",
}
PARADA_FALLBACK = "Parada TRP"
PARADA_INGRESO  = "Parada"

def norm_base(s):
    s = str(s).strip().upper()
    for a, b in [("Á","A"),("É","E"),("Í","I"),("Ó","O"),("Ú","U"),("Ñ","N")]:
        s = s.replace(a, b)
    return s

def norm_empresa_key(s):
    n = norm_base(s)
    return EMP_ALIASES.get(n, n)

def canon_empresa(s):
    key = norm_empresa_key(s)
    return CANON.get(key, str(s).strip())

def norm_ruta(s):
    s = re.sub(r"^RDD\s*-\s*", "", str(s).strip(), flags=re.IGNORECASE)
    return norm_base(s)

def is_spot(ruta):
    return "SPOT" in norm_base(str(ruta))

def es_parada_valida(val):
    """Detecta si un string parece nombre de parada real vs texto libre."""
    if not val or str(val).strip() in ["", "nan", "NaN", "None"]: return False
    v = str(val).strip()
    # Patrones que NO son paradas: hora, "por confirmar", "estimado", solo números
    if re.match(r"^\d{1,2}:\d{2}", v): return False
    if any(p in v.upper() for p in ["CONFIRMAR","ESTIMADO","LLEGADA","SALIDA ","HORARIO","POR CONFIRMAR"]): return False
    if re.match(r"^\d+$", v): return False
    return True

# ══════════════════════════════════════════════════════════════════════════════
# PARSERS
# ══════════════════════════════════════════════════════════════════════════════
def parse_hora(val):
    if val is None or (isinstance(val, float) and pd.isna(val)): return "00:00"
    if isinstance(val, datetime): return val.strftime("%H:%M")
    if isinstance(val, timedelta):
        t = int(val.total_seconds())
        return f"{t//3600:02d}:{(t%3600)//60:02d}"
    if isinstance(val, (int, float)):
        frac = val - int(val)
        tm = round(frac * 1440)
        return f"{(tm//60)%24:02d}:{tm%60:02d}"
    s = str(val).strip()
    m = re.match(r"(\d{1,2}):(\d{2})", s)
    return f"{int(m.group(1)):02d}:{m.group(2)}" if m else "00:00"

def sumar15(h):
    m = re.match(r"^(\d{1,2}):(\d{2})$", h)
    if not m: return h
    t = int(m.group(1))*60 + int(m.group(2)) + 15
    t %= 1440
    return f"{t//60:02d}:{t%60:02d}"

def h2min(h):
    m = re.match(r"^(\d{1,2}):(\d{2})$", h)
    return int(m.group(1))*60 + int(m.group(2)) if m else 0

def parse_fecha_ar(val):
    if val is None or (isinstance(val, float) and pd.isna(val)): return ""
    if isinstance(val, datetime): return val.strftime("%d/%m/%Y")
    s = str(val).split(",")[0].strip()
    m = re.match(r"(\d{1,2})[/\-](\d{1,2})[/\-](\d{4})", s)
    return f"{int(m.group(1)):02d}/{int(m.group(2)):02d}/{m.group(3)}" if m else s

def parse_hora_ar(val):
    if val is None or (isinstance(val, float) and pd.isna(val)): return "00:00"
    if isinstance(val, datetime): return val.strftime("%H:%M")
    parts = str(val).split(",")
    return parse_hora(parts[1].strip()) if len(parts) > 1 else parse_hora(val)

def fecha_a_serial_excel(fecha_str):
    """Convierte dd/mm/yyyy a serial Excel (igual que HTML anterior)."""
    m = re.match(r"(\d{2})/(\d{2})/(\d{4})", str(fecha_str))
    if not m:
        m = re.match(r"(\d{2})-(\d{2})-(\d{4})", str(fecha_str))
    if not m: return 0
    d, mo, y = int(m.group(1)), int(m.group(2)), int(m.group(3))
    try:
        base = date(1900, 1, 1)
        target = date(y, mo, d)
        delta = (target - base).days + 2  # +2 por bug bisiesto Excel 1900
        return delta
    except: return 0

def detectar_col(cols, candidates):
    cn = {norm_base(c): c for c in cols}
    for c in candidates:
        if norm_base(c) in cn: return cn[norm_base(c)]
    return None

def safe_str(val):
    if val is None or (isinstance(val, float) and pd.isna(val)): return ""
    return str(val).split("\n")[0].strip()

def extraer_ultima_parada(recorrido_str):
    if not recorrido_str or str(recorrido_str).strip() in ["", "nan", "NaN", "None"]:
        return None
    s = str(recorrido_str).strip()
    for sep in ["\n", ";", "|", " → ", " -> "]:
        if sep in s:
            parts = [p.strip() for p in s.split(sep) if p.strip()]
            if parts: return parts[-1]
    lines = [l.strip() for l in s.splitlines() if l.strip()]
    if len(lines) > 1: return lines[-1]
    if " - " in s:
        parts = [p.strip() for p in s.split(" - ") if p.strip()]
        if len(parts) > 1: return parts[-1]
    return None

def stops_empresa(stops_df, empresa_key):
    result = set()
    for _, row in stops_df.iterrows():
        comunidades = str(row.get("Comunidades", ""))
        partes = [norm_empresa_key(p.strip()) for p in re.split(r"[,;]", comunidades)]
        if empresa_key in partes:
            result.add(str(row["Nombre parada"]).strip())
    return result

def gen_zip(archivos):
    buf = BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        for nombre, data in archivos.items():
            zf.writestr(nombre, data)
    return buf.getvalue()

