def gen_stops_creation(paradas):
    wb = openpyxl.load_workbook(BytesIO(tmpl_bytes(TMPL_STOPS)))
    ws = wb.active
    font = Font(name="Calibri", size=11)
    for i, p in enumerate(paradas, 2):
        ws.cell(i,1, p["Nombre parada"]).font = font
        ws.cell(i,2, "").font = font
        ws.cell(i,3, "").font = font
        ws.cell(i,4, p["Empresa"]).font = font
        ws.cell(i,5, "Sí").font = font
        ws.cell(i,6, p["Nombre parada"]).font = font
    buf = BytesIO(); wb.save(buf); return buf.getvalue()

def gen_routes_creation(rutas):
    wb = openpyxl.load_workbook(BytesIO(tmpl_bytes(TMPL_ROUTES)))
    ws = wb.active
    for row in ws.iter_rows(min_row=2, max_row=ws.max_row):
        for cell in row: cell.value = None
    font = Font(name="Calibri", size=11)
    for i, r in enumerate(rutas, 2):
        tipo   = str(r.get("Tipo mov","")).upper()
        bodega = str(r.get("Bodega","")).strip()
        if "SALIDA" in tipo:
            origen  = bodega or "Parada"
            destino = PARADA_FALLBACK
        else:
            origen  = PARADA_INGRESO
            destino = bodega or "Parada"
        ws.cell(i, 1, r["Nombre ruta"]).font = font
        ws.cell(i, 2, r["Nombre ruta"]).font = font
        ws.cell(i, 3, None)                        # Shape — vacío
        ws.cell(i, 4, "Ida").font = font
        ws.cell(i, 5, origen).font = font
        ws.cell(i, 6, destino).font = font
        ws.cell(i, 7, "-").font = font
        ws.cell(i,19, "Si").font = font
        ws.cell(i,22, r["Empresa"]).font = font
    buf = BytesIO(); wb.save(buf); return buf.getvalue()

def gen_edicion_horarios(editar_filas, tmpl_file=None):
    """Genera archivo de edición con todas las columnas requeridas.
    - Incluye ID de salida cuando existe (desde el export AllRide o desde la plantilla).
    - Respeta el formato (fuente) que ya trae la plantilla.
    - Solo incluye viajes cuya hora realmente cambia.
    """
    font = Font(name="Calibri", size=11)

    # Filtro defensivo: solo viajes que de verdad requieren edición de horario
    editar_filas = [e for e in editar_filas if str(e.get("hora_actual","")).strip() != str(e.get("hora_nueva","")).strip()]

    if tmpl_file:
        wb = openpyxl.load_workbook(BytesIO(tmpl_file.read()))
        ws = wb.active
        header = [ws.cell(1,c).value for c in range(1, ws.max_column+2)]
        def fc(names):
            for n in names:
                for i,h in enumerate(header):
                    if h and norm_base(str(h)) == norm_base(n): return i+1
            return None
        col_id        = fc(["ID de servicio","ID"])
        col_id_salida = fc(["ID de salida"])
        col_hora      = fc(["Hora del servicio","Hora de inicio","Hora"])
        col_ruta      = fc(["Ruta","Nombre ruta"])
        col_tipo      = fc(["Tipo"])
        col_estado    = fc(["Estado"])
        col_fecha_svc = fc(["Fecha de servicio","Fecha estimada de inicio","Fecha de inicio","Fecha"])
        col_com       = fc(["Comunidades"])

        # Guarda el formato (fuente) de cada columna, y arma un lookup de ID de salida
        # a partir de los datos originales de la plantilla, ANTES de borrar filas.
        col_fonts = {}
        id_salida_lookup = {}
        for c in range(1, ws.max_column+1):
            sample = ws.cell(2, c)
            col_fonts[c] = copy(sample.font) if sample.font else font
        if col_id and col_id_salida:
            for r in range(2, ws.max_row+1):
                sid = safe_str(ws.cell(r, col_id).value)
                sal = safe_str(ws.cell(r, col_id_salida).value)
                if sid and sal:
                    id_salida_lookup[sid] = sal

        ws.delete_rows(2, ws.max_row)
        for i, e in enumerate(editar_filas, 2):
            ar = e["ar_row"]
            id_svc    = ar["id"]
            id_salida = safe_str(ar.get("id_salida","")) or id_salida_lookup.get(id_svc, "")
            if col_id:        ws.cell(i, col_id,    id_svc).font = col_fonts.get(col_id, font)
            if col_id_salida: ws.cell(i, col_id_salida, id_salida).font = col_fonts.get(col_id_salida, font)
            if col_hora:      ws.cell(i, col_hora,  e["hora_nueva"]).font = col_fonts.get(col_hora, font)
            if col_ruta:      ws.cell(i, col_ruta,  ar["ruta_orig"]).font = col_fonts.get(col_ruta, font)
            if col_tipo:      ws.cell(i, col_tipo,  ar["tipo_orig"]).font = col_fonts.get(col_tipo, font)
            if col_estado:    ws.cell(i, col_estado,ar["estado"]).font = col_fonts.get(col_estado, font)
            if col_fecha_svc: ws.cell(i, col_fecha_svc, ar["fecha"]).font = col_fonts.get(col_fecha_svc, font)
            if col_com:       ws.cell(i, col_com,   ar["empresa_orig"]).font = col_fonts.get(col_com, font)
        buf = BytesIO(); wb.save(buf); return buf.getvalue()

    # Sin plantilla: tabla completa
    rows = [{
        "ID de servicio": e["ar_row"]["id"],
        "ID de salida": safe_str(e["ar_row"].get("id_salida","")),
        "Comunidades": e["ar_row"]["empresa_orig"],
        "Tipo": e["ar_row"]["tipo_orig"],
        "Estado": e["ar_row"]["estado"],
        "Ruta": e["ar_row"]["ruta_orig"],
        "Fecha de servicio": e["ar_row"]["fecha"],
        "Hora actual": e["hora_actual"],
        "Hora nueva": e["hora_nueva"],
    } for e in editar_filas]
    buf = BytesIO()
    pd.DataFrame(rows).to_excel(buf, index=False)
    return buf.getvalue()

def gen_one_time_services_ots(crear_filas):
    """
    Genera OTS con fecha como serial Excel + numFmtId=14 (igual que HTML).
    Usa openpyxl con number_format 'DD-MM-YYYY' que fuerza el tipo numérico.
    """
    por_emp = {}
    for row in crear_filas:
        if row["es_spot"]: continue
        por_emp.setdefault(row["empresa_canon"], []).append(row)

    archivos = {}
    for emp, rows in por_emp.items():
        wb = openpyxl.load_workbook(BytesIO(tmpl_bytes(TMPL_OTS)))
        ws = wb.active
        for r in ws.iter_rows(min_row=2, max_row=ws.max_row):
            for c in r: c.value = None
        font = Font(name="Calibri", size=11)
        for i, row in enumerate(rows, 2):
            # Ruta
            ws.cell(i, 1, row["ruta_orig"]).font = font
            # Fecha como serial Excel
            serial = fecha_a_serial_excel(row["fecha"])
            cell_fecha = ws.cell(i, 2, serial)
            cell_fecha.font = font
            cell_fecha.number_format = "DD-MM-YYYY"  # openpyxl usa numFmtId compatible
            # Hora como texto
            ws.cell(i, 3, row["hora_allride"]).font = font
            # Cantidad vehículos
            ws.cell(i, 4, 1).font = font

        buf = BytesIO(); wb.save(buf)
        nombre = re.sub(r"[^\w\-]", "_", emp)[:40]
        archivos[f"one_time_services_{nombre}.xlsx"] = buf.getvalue()
    return archivos

def gen_odd_spots(crear_filas, stops_df):
    por_emp = {}
    for row in crear_filas:
        if not row["es_spot"]: continue
        por_emp.setdefault(row["empresa_canon"], []).append(row)

    stops_cache = {}
    archivos    = {}

    for emp, rows in por_emp.items():
        emp_key = norm_empresa_key(emp)
        if emp_key not in stops_cache:
            stops_cache[emp_key] = stops_empresa(stops_df, emp_key)
        emp_stops = stops_cache[emp_key]

        wb = openpyxl.load_workbook(BytesIO(tmpl_bytes(TMPL_ODD)))
        ws = wb.active
        for r in ws.iter_rows(min_row=2, max_row=ws.max_row):
            for c in r: c.value = None
        font = Font(name="Calibri", size=11)

        for i, row in enumerate(rows, 2):
            tipo_mov  = str(row.get("tipo_mov","")).upper()
            bodega    = str(row.get("bodega","")).strip()
            recorrido = str(row.get("recorrido","")).strip()
            es_salida = "SALIDA" in tipo_mov

            ultima = extraer_ultima_parada(recorrido)

            if es_salida:
                # Origen: parada_origen + parada_usuario (sin destino)
                npo = bodega if bodega and bodega in emp_stops else PARADA_FALLBACK
                # parada destino: última del recorrido
                parada_dest_raw = ultima
                npd = None  # No se llena en Origen según nueva lógica
                parada_usuario = parada_dest_raw if es_parada_valida(parada_dest_raw) and parada_dest_raw in emp_stops else PARADA_FALLBACK
                od = "Origen"
            else:
                # Destino: parada_destino + parada_usuario (sin origen)
                npo = None
                npd = bodega if bodega and bodega in emp_stops else PARADA_INGRESO
                parada_usuario_raw = ultima
                parada_usuario = parada_usuario_raw if es_parada_valida(parada_usuario_raw) else PARADA_INGRESO
                od = "Destino"

            ws.cell(i, 1, i-1).font = font
            ws.cell(i, 2, row["ruta_orig"]).font = font
            ws.cell(i, 3, "Servicios Dinámicos").font = font
            ws.cell(i, 4, od).font = font
            ws.cell(i, 5, row["fecha"]).font = font
            ws.cell(i, 6, row["hora_allride"]).font = font
            ws.cell(i, 7, npo if npo else "").font = font   # Parada origen (vacío si Destino)
            ws.cell(i, 8, npd if npd else "").font = font   # Parada destino (vacío si Origen)
            ws.cell(i, 9, parada_usuario).font = font
            ws.cell(i,10, 1).font = font
            ws.cell(i,11, "").font = font
            ws.cell(i,12, "").font = font
            ws.cell(i,13, "").font = font
            ws.cell(i,14, emp).font = font

        buf = BytesIO(); wb.save(buf)
        nombre = re.sub(r"[^\w\-]", "_", emp)[:40]
        archivos[f"ODD_SPOTS_{nombre}.xlsx"] = buf.getvalue()
    return archivos

def gen_cancelacion(cancelar_filas, tmpl_file_bytes):
    """Genera archivo solo con las filas a cancelar (no todas)."""
    ids = set(str(r["id"]) for r in cancelar_filas)
    wb  = openpyxl.load_workbook(BytesIO(tmpl_file_bytes))
    ws  = wb.active

    header = [ws.cell(1,c).value for c in range(1, ws.max_column+2)]
    try: col_id = header.index("ID de servicio")+1
    except: col_id = 1
    try: col_cancel = header.index("Cancelar")+1
    except: col_cancel = ws.max_column

    # Marcar con X solo los que cancelar, eliminar los que NO cancelar
    rows_to_delete = []
    for r in range(2, ws.max_row+1):
        id_val = str(ws.cell(r, col_id).value or "").strip()
        if not id_val: continue
        if id_val in ids:
            ws.cell(r, col_cancel).value = "X"
            ws.cell(r, col_cancel).font = Font(name="Calibri", size=12, bold=True, color="C0392B")
            ws.cell(r, col_cancel).fill = PatternFill("solid", fgColor="FDEDEC")
            ws.cell(r, col_cancel).alignment = Alignment(horizontal="center")
        else:
            rows_to_delete.append(r)

    # Eliminar filas que NO se cancelan (de abajo hacia arriba)
    for r in reversed(rows_to_delete):
        ws.delete_rows(r)

    buf = BytesIO(); wb.save(buf); return buf.getvalue()

def gen_consolidado_no_editados(editar_filas_no_sel, cli_raw, hoja):
    """Genera excel igual al consolidado pero solo con los viajes no seleccionados para editar."""
    # Obtener índices originales de los no seleccionados
    rutas_no_sel = set()
    for e in editar_filas_no_sel:
        rutas_no_sel.add((e["ar_row"]["fecha"], e["ar_row"]["ruta_norm"], e["ar_row"]["empresa_key"], e["hora_nueva"]))

    buf = BytesIO()
    cli_raw.to_excel(buf, index=False, sheet_name=hoja)
    return buf.getvalue()

